UPDATE check_record_category_stats_new cs
SET
    deduction_count = (
        SELECT COUNT(*) FROM check_record_deductions_new d WHERE d.category_stat_id = cs.id
    ),
    total_score = (
        SELECT COALESCE(SUM(d.actual_score), 0) FROM check_record_deductions_new d WHERE d.category_stat_id = cs.id
    )
WHERE cs.id = #{categoryStatId}
